import { useEffect, useState } from "react";
import type * as THREE from "three";

import type { ReactiveNode } from "../nodes/node";
import type { NodeInfo } from "./graph";
import { buildGraph } from "./graph";
import { NodeCard } from "./node-card";

export type NodeGraphViewerProps = {
  sinkNodes: ReactiveNode<Record<string, unknown>, unknown>[];
  renderer?: THREE.WebGLRenderer;
  onClose: () => void;
};

export function NodeGraphViewer({ sinkNodes, renderer, onClose }: NodeGraphViewerProps) {
  const [graph, setGraph] = useState<Map<string, NodeInfo>>(new Map());
  // const [, forceUpdate] = useState({});

  useEffect(() => {
    setGraph(buildGraph(sinkNodes));
  }, [sinkNodes]);

  // Refresh periodically to show updated outputs
  // useEffect(() => {
  //   const interval = setInterval(() => forceUpdate({}), 500);
  //   return () => clearInterval(interval);
  // }, []);

  // Group nodes by depth
  const nodesByDepth = new Map<number, NodeInfo[]>();
  Array.from(graph.values()).forEach(node => {
    const list = nodesByDepth.get(node.depth) ?? [];
    list.push(node);
    nodesByDepth.set(node.depth, list);
  });
  const maxDepth = Math.max(0, ...Array.from(nodesByDepth.keys()));

  return (
    <div className="fixed left-0 right-0 top-0 bottom-0 bg-black/80 z-50 flex items-center justify-center">
      <div className="bg-gray-900 rounded-lg p-6 max-w-[90vw] max-h-[90vh] overflow-auto">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-xl font-bold text-white">Node Graph</h2>
          <button
            onClick={onClose}
            className="px-3 py-1 bg-gray-700 hover:bg-gray-600 rounded text-white"
          >
            Close
          </button>
        </div>
        <div className="flex gap-8">
          {/* Render columns from sinks (left) to sources (right) */}
          {Array.from({ length: maxDepth + 1 }, (_, depth) => (
            <div key={depth} className="flex flex-col gap-4">
              <div className="text-xs text-gray-500 text-center">
                {depth === 0 ? "Sinks" : depth === maxDepth ? "Sources" : `Depth ${depth}`}
              </div>
              {(nodesByDepth.get(depth) ?? []).map(info => (
                <NodeCard key={info.id} info={info} renderer={renderer} />
              ))}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
