import { useEffect, useRef } from "react";
import type * as THREE from "three";

export function TexturePreview({ texture }: { texture: THREE.Texture }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  console.log(texture.image);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || !texture.image) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const img = texture.image;
    if (img instanceof HTMLImageElement || img instanceof HTMLCanvasElement || img instanceof ImageBitmap) {
      ctx.drawImage(img, 0, 0, 80, 80);
    }
  }, [texture]);

  return <canvas ref={canvasRef} width={80} height={80} className="border border-gray-600" />;
}
