import * as THREE from "three";

import { DefaultPreview } from "./default-preview";
import { GeometryPreview } from "./geometry-preview";
import { MaterialPreview } from "./material-preview";
import { RenderTargetPreview } from "./render-target-preview";
import { TexturePreview } from "./texture-preview";

export type OutputPreviewProps = {
  value: unknown;
  renderer?: THREE.WebGLRenderer;
};

function isDrawableImage(img: unknown): img is HTMLImageElement | HTMLCanvasElement | ImageBitmap {
  return img instanceof HTMLImageElement || img instanceof HTMLCanvasElement || img instanceof ImageBitmap;
}

export function OutputPreview({ value, renderer }: OutputPreviewProps) {
  if (value instanceof THREE.Texture) {
    if (isDrawableImage(value.image)) return <TexturePreview texture={value} />;
    if (value.renderTarget && renderer) return <RenderTargetPreview texture={value} renderer={renderer} />;
    return <DefaultPreview value={value} />;
  } else if (value instanceof THREE.Material) {
    return <MaterialPreview material={value} />;
  } else if (value instanceof THREE.BufferGeometry) {
    return <GeometryPreview geometry={value} />;
  } else {
    return <DefaultPreview value={value} />;
  }
}
