import { useEffect, useRef } from "react";
import type * as THREE from "three";

export function RenderTargetPreview({ texture, renderer }: { texture: THREE.Texture; renderer: THREE.WebGLRenderer }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const rt = texture.renderTarget;
    if (!canvas || !rt) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const width = rt.width;
    const height = rt.height;
    const pixels = new Uint8Array(width * height * 4);

    renderer.readRenderTargetPixels(rt as THREE.WebGLRenderTarget, 0, 0, width, height, pixels);

    const imageData = new ImageData(new Uint8ClampedArray(pixels), width, height);
    const tempCanvas = document.createElement("canvas");
    tempCanvas.width = width;
    tempCanvas.height = height;
    tempCanvas.getContext("2d")!.putImageData(imageData, 0, 0);

    // Flip Y and scale
    ctx.save();
    ctx.translate(0, 150);
    ctx.scale(1, -1);
    ctx.drawImage(tempCanvas, 0, 0, 150, 150);
    ctx.restore();
  }, [texture, renderer]);

  return <canvas ref={canvasRef} width={150} height={150} className="border border-gray-600 bg-gray-800" />;
}
